# === CELL 5: SharePoint Sync and Quiet Share Dashboard ===



"""

Stage 5 dashboard:

- Show all Stage 4 reviewer subfolders.

- Allow cherry-pick upload and SPO Edit grant via two checkboxes per row.

- Re-validate reviewer identity (full name or email) against AD in real time.

- Sync selected folders to SharePoint and grant Edit permission on selected reviewer folders.

"""



import os

import re

import glob

import json

import base64

import html
import time

from datetime import datetime

from urllib.parse import quote, urlparse, unquote



import requests

import pandas as pd

import ipywidgets as widgets

from dotenv import load_dotenv
from msal import PublicClientApplication

from IPython.display import display, clear_output



# ============================================

# Paths and constants

# ============================================



today_str = datetime.now().strftime('%Y-%m-%d')

BASE_DIR = os.path.join("output", today_str, "user-listing")

STAGE4_ROOT_DIR = os.path.join(BASE_DIR, "stage4_reviewer_splitter")
STAGE4_FALLBACK_APP_DIR = os.path.join(STAGE4_ROOT_DIR, "excel_reviewer_splitter")

INPUT_AD_CACHE_DIR = os.path.join("input", "ad_cache")

OUTPUT_AD_CACHE_DIR = os.path.join(BASE_DIR, "ad_cache")

SHAREPOINT_HOST_DEFAULT = "davidshih.sharepoint.com"
SITE_NAME_DEFAULT = "aer"
BASE_PATH_DEFAULT = "2026 Entitlement Review"

def _normalize_sharepoint_host(value):
    raw = str(value or "").strip().lower()
    if raw.startswith("https://"):
        raw = raw[len("https://"):]
    elif raw.startswith("http://"):
        raw = raw[len("http://"):]
    raw = raw.split("/", 1)[0].strip()
    return raw


load_dotenv(override=True)

SHAREPOINT_HOST = _normalize_sharepoint_host(os.getenv("SHAREPOINT_HOST", SHAREPOINT_HOST_DEFAULT))
SITE_NAME = str(os.getenv("SITE_NAME", SITE_NAME_DEFAULT)).strip().strip("/")
BASE_PATH = str(os.getenv("BASE_PATH", BASE_PATH_DEFAULT)).strip().strip("/")
if not BASE_PATH:
    BASE_PATH = str(os.getenv("APP_NAME", BASE_PATH_DEFAULT)).strip().strip("/")



REQUIRED_SCOPES = {

    "User.Read.All",

    "Files.ReadWrite",

    "Sites.Read.All",

}
SPO_EDIT_ROLE_NAME = "Edit"
SPO_FALLBACK_ROLEDEF_ID = 1073741827
SPO_REQUEST_TIMEOUT_SEC = 30



EMAIL_PATTERN = re.compile(r'^[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.[A-Za-z]{2,}$')

s5_digest_cache = {}



# ============================================

# Helpers: token and Graph

# ============================================



def _extract_bearer_token(headers_obj):

    if not isinstance(headers_obj, dict):

        return ""

    auth = str(headers_obj.get("Authorization", "")).strip()

    if not auth.lower().startswith("bearer "):

        return ""

    return auth.split(" ", 1)[1].strip()





def _decode_jwt_payload(token):

    try:

        parts = token.split('.')

        if len(parts) < 2:

            return {}

        payload_raw = parts[1] + ('=' * (-len(parts[1]) % 4))

        payload = base64.urlsafe_b64decode(payload_raw.encode('utf-8')).decode('utf-8')

        return json.loads(payload)

    except Exception:

        return {}





def _get_token_scopes(token):

    payload = _decode_jwt_payload(token)

    scope_str = str(payload.get('scp', '')).strip()

    if not scope_str:

        return set()

    return set(scope_str.split())





def _get_graph_headers_from_stage1():

    stage1_headers_local = globals().get("stage1_headers", {})

    token = _extract_bearer_token(stage1_headers_local)

    if not token:

        return None, "Missing Stage 1 token. Run Cell 1 login first."



    granted_scopes = _get_token_scopes(token)

    missing = sorted(list(REQUIRED_SCOPES - granted_scopes))

    if missing:

        return None, f"Stage 1 token missing scopes: {', '.join(missing)}"



    return {"Authorization": f"Bearer {token}"}, ""



def _get_spo_headers_from_stage1():

    stage1_spo_headers_local = globals().get("stage1_spo_headers", {})

    token = _extract_bearer_token(stage1_spo_headers_local)

    spo_host = _normalize_sharepoint_host(globals().get("stage1_spo_host", ""))

    if token and not spo_host:

        spo_host = _normalize_sharepoint_host(_read_env_or_global("SHAREPOINT_HOST"))

        if spo_host:

            globals()["stage1_spo_host"] = spo_host



    if token and spo_host:

        return {"Authorization": f"Bearer {token}"}, spo_host, ""



    load_dotenv(override=True)

    tid = str(os.getenv("AZURE_TENANT_ID", "")).strip()

    cid = str(os.getenv("AZURE_CLIENT_ID", "")).strip()

    spo_host = _normalize_sharepoint_host(os.getenv("SHAREPOINT_HOST", ""))

    if not spo_host:

        spo_host = _normalize_sharepoint_host(globals().get("SHAREPOINT_HOST", ""))



    if not spo_host:

        return None, "", (

            "Missing SharePoint host. Set SHAREPOINT_HOST in .env and retry."

        )

    if not tid or not cid:

        return None, spo_host, (

            "Missing AZURE_TENANT_ID or AZURE_CLIENT_ID in .env. "

            "Cannot acquire SharePoint token in Stage 5."

        )



    try:

        app = PublicClientApplication(

            cid,

            authority=f"https://login.microsoftonline.com/{tid}"

        )

        spo_scopes = [f"https://{spo_host}/AllSites.FullControl"]

        spo_result = None

        accounts = app.get_accounts()

        if accounts:

            spo_result = app.acquire_token_silent(scopes=spo_scopes, account=accounts[0])

        if not spo_result or "access_token" not in spo_result:

            spo_result = app.acquire_token_interactive(scopes=spo_scopes, prompt="select_account")



        if "access_token" not in spo_result:

            error_msg = spo_result.get("error_description", "Unknown error") if isinstance(spo_result, dict) else "Unknown error"

            return None, spo_host, f"SharePoint token acquisition failed: {error_msg}"



        token = spo_result["access_token"]

        spo_headers = {"Authorization": f"Bearer {token}"}

        globals()["stage1_spo_headers"] = spo_headers

        globals()["stage1_spo_host"] = spo_host

        return spo_headers, spo_host, ""

    except Exception as e:

        return None, spo_host, f"SharePoint token acquisition error: {str(e)}"

def _build_share_id_from_url(url):

    encoded = base64.urlsafe_b64encode(url.encode('utf-8')).decode('utf-8').rstrip('=')

    return f"u!{encoded}"



def _read_env_or_global(name, default=""):
    load_dotenv(override=True)

    env_val = str(os.getenv(name, "")).strip()

    if env_val:

        return env_val

    global_val = globals().get(name, default)

    return str(global_val or "").strip()



def _resolve_target_folder_from_url(target_url, headers):

    share_id = _build_share_id_from_url(target_url)

    endpoint = f"https://graph.microsoft.com/v1.0/shares/{share_id}/driveItem"

    resp = requests.get(endpoint, headers=headers)

    if resp.status_code >= 400:

        raise RuntimeError(f"Target URL resolve failed ({resp.status_code}): {resp.text[:300]}")



    data = resp.json()

    if 'folder' not in data:

        raise RuntimeError("Provided URL is not a SharePoint folder")



    drive_id = data.get('parentReference', {}).get('driveId')

    item_id = data.get('id')

    web_url = data.get('webUrl', target_url)



    if not drive_id or not item_id:

        raise RuntimeError("Unable to resolve target drive/item from URL")



    return {

        "drive_id": drive_id,

        "item_id": item_id,

        "web_url": web_url,

        "target_source": "url",

    }



def _resolve_target_folder_from_env(headers):

    sharepoint_host = _read_env_or_global("SHAREPOINT_HOST")

    site_name = _read_env_or_global("SITE_NAME")

    base_path = _read_env_or_global("BASE_PATH")

    if not base_path:

        base_path = _read_env_or_global("APP_NAME")

    if not sharepoint_host or not site_name:

        raise RuntimeError(

            "SharePoint folder URL is blank and fallback requires SHAREPOINT_HOST + SITE_NAME "

            "(plus BASE_PATH or APP_NAME)."

        )

    site_name_clean = site_name.strip("/")

    if not site_name_clean:

        raise RuntimeError("Fallback SITE_NAME is blank after trimming.")

    site_endpoint = f"https://graph.microsoft.com/v1.0/sites/{sharepoint_host}:/sites/{quote(site_name_clean, safe='/')}"

    site_resp = requests.get(site_endpoint, headers=headers, timeout=SPO_REQUEST_TIMEOUT_SEC)

    if site_resp.status_code >= 400:

        raise RuntimeError(

            f"Resolve site from fallback failed ({site_resp.status_code}): {site_resp.text[:300]}"

        )

    site_data = _safe_json_response(site_resp)

    site_id = str(site_data.get("id", "")).strip() if isinstance(site_data, dict) else ""

    if not site_id:

        raise RuntimeError("Fallback site id missing from Graph response.")

    base_path_clean = str(base_path or "").strip().strip("/")

    if not base_path_clean:

        folder_endpoint = f"https://graph.microsoft.com/v1.0/sites/{site_id}/drive/root"

    else:

        folder_endpoint = (

            f"https://graph.microsoft.com/v1.0/sites/{site_id}/drive/root:/{quote(base_path_clean, safe='/')}"

        )

    folder_resp = requests.get(folder_endpoint, headers=headers, timeout=SPO_REQUEST_TIMEOUT_SEC)

    if folder_resp.status_code >= 400:

        raise RuntimeError(

            f"Resolve fallback folder failed ({folder_resp.status_code}): {folder_resp.text[:300]}"

        )

    folder_data = _safe_json_response(folder_resp)

    if "folder" not in folder_data:

        raise RuntimeError(

            "Fallback BASE_PATH/APP_NAME does not point to a folder. "

            "Please set SP Folder URL directly or correct env values."

        )

    drive_id = str(folder_data.get("parentReference", {}).get("driveId", "")).strip()

    item_id = str(folder_data.get("id", "")).strip()

    web_url = str(folder_data.get("webUrl", "")).strip()

    if not drive_id or not item_id:

        raise RuntimeError("Fallback folder resolve returned missing drive/item id.")

    return {

        "drive_id": drive_id,

        "item_id": item_id,

        "web_url": web_url,

        "target_source": "env",

        "fallback_site": f"{sharepoint_host}/sites/{site_name_clean}",

        "fallback_path": base_path_clean or "/",

    }



def _resolve_target_folder(target_url, headers):

    target_url_clean = str(target_url or "").strip()

    if target_url_clean:

        return _resolve_target_folder_from_url(target_url_clean, headers)

    raise RuntimeError(

        "No target folder selected. Paste SP Folder URL or choose one from the tree first."

    )



def _resolve_user_object_id(target_email, headers):

    email = str(target_email).strip().lower()

    if not email:

        return "", "blank email"

    escaped = email.replace("'", "''")

    filter_q = quote(f"mail eq '{escaped}' or userPrincipalName eq '{escaped}'")

    endpoint = (
        "https://graph.microsoft.com/v1.0/users"
        f"?$filter={filter_q}&$select=id,mail,userPrincipalName&$top=2"
    )

    resp = requests.get(endpoint, headers=headers)

    if resp.status_code >= 400:

        return "", f"user lookup failed ({resp.status_code})"

    data = _safe_json_response(resp)

    values = data.get('value', []) if isinstance(data, dict) else []

    if not values:

        return "", "user lookup returned no match"

    exact = []

    for u in values:

        if not isinstance(u, dict):

            continue

        m = str(u.get('mail', '')).strip().lower()

        upn = str(u.get('userPrincipalName', '')).strip().lower()

        if email in {m, upn}:

            exact.append(u)

    candidate = exact[0] if exact else values[0]

    oid = str(candidate.get('id', '')).strip()

    if not oid:

        return "", "user object id missing from Graph response"

    return oid, ""



def _list_children(drive_id, parent_item_id, headers):

    items = []

    url = f"https://graph.microsoft.com/v1.0/drives/{drive_id}/items/{parent_item_id}/children?$top=999"



    while url:

        resp = requests.get(url, headers=headers)

        if resp.status_code >= 400:

            raise RuntimeError(f"List children failed ({resp.status_code}): {resp.text[:300]}")

        data = resp.json()

        items.extend(data.get('value', []))

        url = data.get('@odata.nextLink')



    return items





def _find_child_folder_by_name(drive_id, parent_item_id, folder_name, headers):

    for item in _list_children(drive_id, parent_item_id, headers):

        if item.get('name') == folder_name and item.get('folder') is not None:

            return item

    return None





def _ensure_child_folder(drive_id, parent_item_id, folder_name, headers):

    existing = _find_child_folder_by_name(drive_id, parent_item_id, folder_name, headers)

    if existing:

        return existing



    endpoint = f"https://graph.microsoft.com/v1.0/drives/{drive_id}/items/{parent_item_id}/children"

    payload = {

        "name": folder_name,

        "folder": {},

        "@microsoft.graph.conflictBehavior": "fail",

    }

    resp = requests.post(endpoint, headers=headers, json=payload)



    if resp.status_code in (200, 201):

        return resp.json()



    if resp.status_code == 409:

        existing_after_conflict = _find_child_folder_by_name(drive_id, parent_item_id, folder_name, headers)

        if existing_after_conflict:

            return existing_after_conflict



    raise RuntimeError(f"Ensure folder failed ({resp.status_code}): {resp.text[:300]}")





def _upload_small_file(drive_id, parent_item_id, file_path, headers):

    file_name = os.path.basename(file_path)

    endpoint = f"https://graph.microsoft.com/v1.0/drives/{drive_id}/items/{parent_item_id}:/{quote(file_name)}:/content"

    with open(file_path, 'rb') as f:

        resp = requests.put(endpoint, headers=headers, data=f.read())

    if resp.status_code >= 400:

        raise RuntimeError(f"Upload failed for {file_name} ({resp.status_code}): {resp.text[:300]}")





def _upload_large_file(drive_id, parent_item_id, file_path, headers):

    file_name = os.path.basename(file_path)

    endpoint = f"https://graph.microsoft.com/v1.0/drives/{drive_id}/items/{parent_item_id}:/{quote(file_name)}:/createUploadSession"

    payload = {

        "item": {

            "@microsoft.graph.conflictBehavior": "replace",

            "name": file_name,

        }

    }



    session_resp = requests.post(endpoint, headers=headers, json=payload)

    if session_resp.status_code >= 400:

        raise RuntimeError(f"Create upload session failed for {file_name}: {session_resp.text[:300]}")



    upload_url = session_resp.json().get('uploadUrl')

    if not upload_url:

        raise RuntimeError(f"Upload session URL missing for {file_name}")



    chunk_size = 5 * 1024 * 1024

    file_size = os.path.getsize(file_path)



    with open(file_path, 'rb') as f:

        start = 0

        while start < file_size:

            data = f.read(chunk_size)

            end = start + len(data) - 1



            put_headers = {

                "Content-Length": str(len(data)),

                "Content-Range": f"bytes {start}-{end}/{file_size}",

            }



            chunk_resp = requests.put(upload_url, headers=put_headers, data=data)

            if chunk_resp.status_code not in (200, 201, 202):

                raise RuntimeError(f"Chunk upload failed for {file_name}: {chunk_resp.text[:300]}")



            start = end + 1





def _upload_file(drive_id, parent_item_id, file_path, headers):

    file_size = os.path.getsize(file_path)

    if file_size <= 4 * 1024 * 1024:

        _upload_small_file(drive_id, parent_item_id, file_path, headers)

    else:

        _upload_large_file(drive_id, parent_item_id, file_path, headers)





def _sync_local_folder_to_remote(local_folder, drive_id, remote_folder_item_id, headers, logger):

    uploaded_files = 0



    folder_cache = {'.': remote_folder_item_id}



    for root, dirs, files in os.walk(local_folder):

        rel_root = os.path.relpath(root, local_folder)

        if rel_root not in folder_cache:

            parent_rel = os.path.dirname(rel_root)

            if parent_rel == '':

                parent_rel = '.'

            parent_id = folder_cache[parent_rel]

            current_name = os.path.basename(rel_root)

            current_folder = _ensure_child_folder(drive_id, parent_id, current_name, headers)

            folder_cache[rel_root] = current_folder['id']



        current_remote_id = folder_cache[rel_root]



        for d in dirs:

            child_rel = d if rel_root == '.' else os.path.join(rel_root, d)

            ensured = _ensure_child_folder(drive_id, current_remote_id, d, headers)

            folder_cache[child_rel] = ensured['id']



        for fn in files:

            fp = os.path.join(root, fn)

            _upload_file(drive_id, current_remote_id, fp, headers)

            uploaded_files += 1

            logger(f"    uploaded: {fn}")



    return uploaded_files





def _safe_json_response(resp):

    try:

        return resp.json()

    except Exception:

        return {}



def _normalize_spo_host(value):

    return str(value or "").strip().lower().split(':', 1)[0]



def _get_spo_site_url_from_folder_web_url(folder_web_url, expected_host):

    parsed = urlparse(str(folder_web_url or "").strip())

    if not parsed.scheme or not parsed.netloc:

        raise RuntimeError(f"Invalid folder webUrl: {folder_web_url}")

    folder_host = _normalize_spo_host(parsed.netloc)

    expected_host_norm = _normalize_spo_host(expected_host)

    if expected_host_norm and folder_host != expected_host_norm:

        raise RuntimeError(

            f"Folder host mismatch. URL host={folder_host}, SHAREPOINT_HOST={expected_host_norm}"

        )

    server_relative_path = unquote(parsed.path or "").strip()

    if not server_relative_path.startswith('/'):

        server_relative_path = '/' + server_relative_path

    if server_relative_path in {'', '/'}:

        raise RuntimeError(f"Invalid server-relative path from URL: {folder_web_url}")

    parts = [p for p in server_relative_path.split('/') if p]

    site_path = ""

    if len(parts) >= 2 and parts[0].lower() in {"sites", "teams"}:

        site_path = '/' + '/'.join(parts[:2])

    site_url = f"https://{folder_host}{site_path}"

    return site_url, server_relative_path



def _spo_json(resp):

    data = _safe_json_response(resp)

    if isinstance(data, dict):

        return data

    return {}



def _spo_base_headers(spo_headers):

    headers = dict(spo_headers or {})

    headers["Accept"] = "application/json;odata=verbose"

    return headers



def _spo_get_form_digest(site_url, spo_headers):

    cache_key = str(site_url).strip().lower()

    now_ts = time.time()

    cache_hit = s5_digest_cache.get(cache_key)

    if cache_hit and isinstance(cache_hit, tuple) and len(cache_hit) == 2:

        digest_value, expire_ts = cache_hit

        if digest_value and now_ts < float(expire_ts):

            return digest_value

    endpoint = f"{site_url}/_api/contextinfo"

    headers = _spo_base_headers(spo_headers)

    headers["Content-Type"] = "application/json;odata=verbose"

    resp = requests.post(endpoint, headers=headers, timeout=SPO_REQUEST_TIMEOUT_SEC)

    if resp.status_code >= 400:

        raise RuntimeError(f"Get SharePoint form digest failed ({resp.status_code}): {resp.text[:300]}")

    data = _spo_json(resp)

    info = data.get('d', {}).get('GetContextWebInformation', {}) if isinstance(data, dict) else {}

    digest_value = str(info.get('FormDigestValue', '')).strip()

    timeout_sec = int(info.get('FormDigestTimeoutSeconds', 1200) or 1200)

    if not digest_value:

        raise RuntimeError("SharePoint form digest missing in contextinfo response")

    expire_ts = now_ts + max(timeout_sec - 60, 60)

    s5_digest_cache[cache_key] = (digest_value, expire_ts)

    return digest_value



def _spo_request(method, endpoint, spo_headers, site_url='', json_payload=None, needs_digest=False):

    headers = _spo_base_headers(spo_headers)

    method_upper = str(method).upper()

    if method_upper != 'GET':

        headers["Content-Type"] = "application/json;odata=verbose"

    if needs_digest:

        if not site_url:

            raise RuntimeError("SharePoint digest requested without site URL")

        headers["X-RequestDigest"] = _spo_get_form_digest(site_url, spo_headers)

    return requests.request(

        method_upper,

        endpoint,

        headers=headers,

        json=json_payload,

        timeout=SPO_REQUEST_TIMEOUT_SEC,

    )



def _spo_get_folder_item_endpoint(site_url, server_relative_path):

    escaped = quote(server_relative_path, safe='/')

    return f"{site_url}/_api/web/GetFolderByServerRelativeUrl('{escaped}')/ListItemAllFields"



def _spo_get_folder_item(site_url, server_relative_path, spo_headers):

    item_endpoint = _spo_get_folder_item_endpoint(site_url, server_relative_path)

    endpoint = f"{item_endpoint}?$select=Id,HasUniqueRoleAssignments"

    resp = _spo_request('GET', endpoint, spo_headers)

    if resp.status_code >= 400:

        raise RuntimeError(f"Get folder list item failed ({resp.status_code}): {resp.text[:300]}")

    data = _spo_json(resp)

    item_data = data.get('d', {}) if isinstance(data, dict) else {}

    return item_endpoint, item_data



def _spo_break_role_inheritance(item_endpoint, site_url, spo_headers):

    endpoint = f"{item_endpoint}/breakroleinheritance(copyRoleAssignments=true,clearSubscopes=false)"

    resp = _spo_request('POST', endpoint, spo_headers, site_url=site_url, needs_digest=True)

    if resp.status_code in (200, 204):

        return 'ok', resp.status_code, resp.text[:500]

    body_lower = str(resp.text or '').lower()

    if resp.status_code in (400, 409) and (

        'already has unique role assignments' in body_lower

        or 'already unique' in body_lower

        or 'uniqueroleassignments' in body_lower

    ):

        return 'already_unique', resp.status_code, resp.text[:500]

    raise RuntimeError(f"Break role inheritance failed ({resp.status_code}): {resp.text[:300]}")



def _spo_ensure_user(site_url, email, spo_headers):

    endpoint = f"{site_url}/_api/web/ensureuser"

    email_lower = str(email).strip().lower()

    candidates = [f"i:0#.f|membership|{email_lower}", email_lower]

    last_error = ''

    for logon_name in candidates:

        payload = {"logonName": logon_name}

        resp = _spo_request('POST', endpoint, spo_headers, site_url=site_url, json_payload=payload, needs_digest=True)

        if resp.status_code >= 400:

            last_error = f"Ensure user failed ({resp.status_code}): {resp.text[:300]}"

            continue

        data = _spo_json(resp)

        principal_id = data.get('d', {}).get('Id') if isinstance(data, dict) else None

        if principal_id is None and isinstance(data, dict):

            principal_id = data.get('Id')

        if principal_id is not None:

            return int(principal_id), resp.status_code, resp.text[:500]

    raise RuntimeError(last_error or "Ensure user failed: principal id not found")



def _spo_get_roledef_id(site_url, role_name, fallback_roledef_id, spo_headers):

    role_name_escaped = str(role_name).replace("'", "''")

    endpoint = f"{site_url}/_api/web/roledefinitions/getbyname('{role_name_escaped}')?$select=Id,Name"

    resp = _spo_request('GET', endpoint, spo_headers)

    if resp.status_code < 400:

        data = _spo_json(resp)

        role_id = data.get('d', {}).get('Id') if isinstance(data, dict) else None

        if role_id is None and isinstance(data, dict):

            role_id = data.get('Id')

        if role_id is not None:

            return int(role_id), 'lookup', resp.status_code, resp.text[:500]

    return int(fallback_roledef_id), 'fallback', resp.status_code, resp.text[:500]



def _spo_add_role_assignment(item_endpoint, site_url, principal_id, roledef_id, spo_headers):

    endpoint = (

        f"{item_endpoint}/roleassignments/addroleassignment(principalid={int(principal_id)},roledefid={int(roledef_id)})"

    )

    resp = _spo_request('POST', endpoint, spo_headers, site_url=site_url, needs_digest=True)

    if resp.status_code in (200, 201, 204):

        return 'granted', resp.status_code, resp.text[:500]

    body_lower = str(resp.text or '').lower()

    if resp.status_code in (400, 409) and (

        'already exists' in body_lower

        or 'already has role assignment' in body_lower

        or 'existing role assignment' in body_lower

        or 'already has permissions' in body_lower

    ):

        return 'already_exists', resp.status_code, resp.text[:500]

    raise RuntimeError(f"Add role assignment failed ({resp.status_code}): {resp.text[:300]}")



def _spo_verify_role_assignment(item_endpoint, principal_id, roledef_id, spo_headers):

    endpoint = (

        f"{item_endpoint}/roleassignments/getbyprincipalid({int(principal_id)})?$expand=RoleDefinitionBindings"

    )

    resp = _spo_request('GET', endpoint, spo_headers)

    if resp.status_code >= 400:

        return False, resp.status_code, resp.text[:500]

    data = _spo_json(resp)

    root = data.get('d', {}) if isinstance(data, dict) else {}

    bindings_obj = root.get('RoleDefinitionBindings', {}) if isinstance(root, dict) else {}

    if isinstance(bindings_obj, dict) and isinstance(bindings_obj.get('results'), list):

        bindings = bindings_obj.get('results', [])

    elif isinstance(bindings_obj, list):

        bindings = bindings_obj

    else:

        bindings = []

    target_roledef_id = int(roledef_id)

    for b in bindings:

        try:

            if int(b.get('Id')) == target_roledef_id:

                return True, resp.status_code, resp.text[:500]

        except Exception:

            continue

    return False, resp.status_code, resp.text[:500]



def _grant_spo_edit_on_root_folder(folder_web_url, target_email, spo_headers, spo_host):

    site_url, server_relative_path = _get_spo_site_url_from_folder_web_url(folder_web_url, spo_host)

    item_endpoint, item_data = _spo_get_folder_item(site_url, server_relative_path, spo_headers)

    root_break_status, break_http_status, break_preview = _spo_break_role_inheritance(item_endpoint, site_url, spo_headers)

    principal_id, ensure_status, ensure_preview = _spo_ensure_user(site_url, target_email, spo_headers)

    roledef_id, role_lookup_mode, role_lookup_status, role_lookup_preview = _spo_get_roledef_id(

        site_url=site_url,

        role_name=SPO_EDIT_ROLE_NAME,

        fallback_roledef_id=SPO_FALLBACK_ROLEDEF_ID,

        spo_headers=spo_headers,

    )

    grant_status, grant_http_status, grant_preview = _spo_add_role_assignment(

        item_endpoint=item_endpoint,

        site_url=site_url,

        principal_id=principal_id,

        roledef_id=roledef_id,

        spo_headers=spo_headers,

    )

    verified, verify_status, verify_preview = _spo_verify_role_assignment(

        item_endpoint=item_endpoint,

        principal_id=principal_id,

        roledef_id=roledef_id,

        spo_headers=spo_headers,

    )

    if not verified:

        raise RuntimeError(

            f"Grant verification failed ({verify_status}). preview={verify_preview[:200]}"

        )

    return {

        'success': True,

        'site_url': site_url,

        'server_relative_path': server_relative_path,

        'root_item_id': item_data.get('Id') if isinstance(item_data, dict) else None,

        'root_break_status': root_break_status,

        'break_status_code': break_http_status,

        'break_preview': break_preview,

        'principal_id': int(principal_id),

        'ensure_status_code': ensure_status,

        'ensure_preview': ensure_preview,

        'roledef_id_used': int(roledef_id),

        'role_lookup_mode': role_lookup_mode,

        'role_lookup_status_code': role_lookup_status,

        'role_lookup_preview': role_lookup_preview,

        'grant_status': grant_status,

        'grant_status_code': grant_http_status,

        'grant_preview': grant_preview,

        'verified': True,

    }



