def _normalize_person_name(name):

    if pd.isna(name):

        return ""

    return re.sub(r'\s+', ' ', str(name).strip().lower())





def _is_email(value):

    return bool(EMAIL_PATTERN.match(str(value).strip().lower()))





def _load_latest_ad_identity_index():

    input_files = glob.glob(os.path.join(INPUT_AD_CACHE_DIR, "ad_users_*.csv"))

    cache_path = max(input_files, key=os.path.getmtime) if input_files else None



    if not cache_path:

        output_files = glob.glob(os.path.join(OUTPUT_AD_CACHE_DIR, "ad_users_*.csv"))

        cache_path = max(output_files, key=os.path.getmtime) if output_files else None



    if not cache_path:

        return False, set(), {}, "", "No AD cache found. Run Cell 1 first."



    try:

        df = pd.read_csv(cache_path)

        required = {"email", "displayName"}

        missing = [c for c in required if c not in df.columns]

        if missing:

            return False, set(), {}, cache_path, f"AD cache missing columns: {missing}"



        email_set = set()

        name_map = {}



        for _, row in df.iterrows():

            email = str(row.get('email', '')).strip().lower()

            if not email or email == 'nan':

                continue



            email_set.add(email)



            n = _normalize_person_name(row.get('displayName', ''))

            if n:

                name_map.setdefault(n, set()).add(email)



        return True, email_set, name_map, cache_path, ""



    except Exception as e:

        return False, set(), {}, cache_path or "", f"Load AD cache failed: {e}"





def _resolve_identity(value, ad_email_set, ad_name_map):

    raw = "" if pd.isna(value) else str(value).strip()

    if raw == "":

        return False, "", "Reviewer value is blank"



    raw_lower = raw.lower()



    if '@' in raw_lower:

        if not _is_email(raw_lower):

            return False, "", "Reviewer email format invalid"

        if raw_lower not in ad_email_set:

            return False, "", "Reviewer email not found in AD"

        return True, raw_lower, ""



    normalized_name = _normalize_person_name(raw)

    matches = sorted(list(ad_name_map.get(normalized_name, set())))

    if len(matches) == 0:

        return False, "", "Reviewer name not found in AD"

    if len(matches) > 1:

        return False, "", f"Reviewer name maps to multiple AD users ({len(matches)})"



    return True, matches[0], ""





def _get_stage4_active_app_dir():

    latest_stage4_output = globals().get("s4_last_output_root", "")

    if latest_stage4_output and os.path.isdir(str(latest_stage4_output)):

        return str(latest_stage4_output)

    if os.path.isdir(STAGE4_FALLBACK_APP_DIR):

        return STAGE4_FALLBACK_APP_DIR

    if not os.path.isdir(STAGE4_ROOT_DIR):

        return ""

    app_dirs = []

    for name in os.listdir(STAGE4_ROOT_DIR):

        p = os.path.join(STAGE4_ROOT_DIR, name)

        if os.path.isdir(p):

            app_dirs.append(p)

    if not app_dirs:

        return ""

    return max(app_dirs, key=os.path.getmtime)


