def _get_picker_site_id(headers, sharepoint_host, site_name):

    endpoint = f"https://graph.microsoft.com/v1.0/sites/{sharepoint_host}:/sites/{quote(site_name, safe='/')}"

    resp = requests.get(endpoint, headers=headers, timeout=SPO_REQUEST_TIMEOUT_SEC)

    if resp.status_code >= 400:

        raise RuntimeError(f"Folder picker failed to resolve site ({resp.status_code}): {resp.text[:300]}")

    data = _safe_json_response(resp)

    site_id = str(data.get("id", "")).strip() if isinstance(data, dict) else ""

    if not site_id:

        raise RuntimeError("Folder picker failed: site id missing.")

    return site_id



def _get_picker_folder_item(headers, site_id, folder_path):

    clean_path = _normalize_rel_path(folder_path)

    if clean_path:

        endpoint = (

            f"https://graph.microsoft.com/v1.0/sites/{site_id}/drive/root:/{quote(clean_path, safe='/')}"

            "?$select=id,name,webUrl,folder,lastModifiedDateTime,createdDateTime"

        )

    else:

        endpoint = (

            f"https://graph.microsoft.com/v1.0/sites/{site_id}/drive/root"

            "?$select=id,name,webUrl,folder,lastModifiedDateTime,createdDateTime"

        )

    resp = requests.get(endpoint, headers=headers, timeout=SPO_REQUEST_TIMEOUT_SEC)

    if resp.status_code >= 400:

        raise RuntimeError(f"Folder picker failed to resolve path ({resp.status_code}): {resp.text[:300]}")

    data = _safe_json_response(resp)

    if "folder" not in data:

        raise RuntimeError("Folder picker target is not a folder.")

    return data



def _list_picker_child_folders(headers, site_id, parent_item_id, parent_path):

    clean_parent = _normalize_rel_path(parent_path)

    item_id = str(parent_item_id or "").strip()

    if not item_id:

        raise RuntimeError("Folder picker missing parent item id for children lookup.")

    url = (

        f"https://graph.microsoft.com/v1.0/sites/{site_id}/drive/items/{item_id}/children"

        "?$top=200&$select=id,name,webUrl,folder,createdDateTime,lastModifiedDateTime"

    )

    folders = []

    while url:

        resp = requests.get(url, headers=headers, timeout=SPO_REQUEST_TIMEOUT_SEC)

        if resp.status_code >= 400:

            raise RuntimeError(

                f"Folder picker list children failed ({resp.status_code}) "

                f"[item_id={item_id} path={clean_parent or '/'}]: {resp.text[:300]}"

            )

        payload = _safe_json_response(resp)

        for item in payload.get("value", []) if isinstance(payload, dict) else []:

            if not isinstance(item, dict) or item.get("folder") is None:

                continue

            name = str(item.get("name", "")).strip()

            if not name:

                continue

            folders.append(

                {

                    "id": str(item.get("id", "")).strip(),

                    "name": name,

                    "path": _join_child_path(clean_parent, name),

                    "web_url": str(item.get("webUrl", "")).strip(),

                    "child_count": int(item.get("folder", {}).get("childCount", 0) or 0),

                    "created": str(item.get("createdDateTime", "")).strip(),

                    "modified": str(item.get("lastModifiedDateTime", "")).strip(),

                }

            )

        url = payload.get("@odata.nextLink") if isinstance(payload, dict) else None

    folders.sort(key=lambda x: x["name"].lower())

    return folders



