                            folder_path=c["path"],

                            folder_web_url=c["web_url"],

                            folder_item_id=c["id"],

                            child_count=c["child_count"],

                            modified=c["modified"],

                            level=level + 1,

                            auto_expand_depth=max(int(auto_expand_depth) - 1, 0),

                        )

