        s5_picker_selected_btn = select_btn

        _set_selected_folder_from_picker(folder_web_url, folder_path, child_count=child_count)

        _set_target_selection_lock(True)

    expand_btn.on_click(on_expand)

    select_btn.on_click(on_select)

    if int(auto_expand_depth) > 0:

        on_expand(None)

    return widgets.VBox([row, children_box])



