    row['upload_chk'].observe(on_upload_change, names='value')

    row['share_chk'].observe(on_share_change, names='value')





def _build_row(folder_name, folder_path):

    upload_chk = widgets.Checkbox(value=True, indent=False, layout=widgets.Layout(width='70px'))

    share_chk = widgets.Checkbox(value=False, indent=False, layout=widgets.Layout(width='120px'))



    folder_html = widgets.HTML(value=f"<b>{html.escape(folder_name)}</b>", layout=widgets.Layout(width='220px'))

    reviewer_input = widgets.Text(value=folder_name, layout=widgets.Layout(width='220px'))

    resolved_email_html = widgets.HTML(value="<span style='color:#999;'>N/A</span>", layout=widgets.Layout(width='260px'))

    ad_status = widgets.HTML(value="", layout=widgets.Layout(width='360px'))

    sync_status = widgets.HTML(value="<span style='color:#999;'>Not run</span>", layout=widgets.Layout(width='180px'))

    share_status = widgets.HTML(value="<span style='color:#999;'>Not run</span>", layout=widgets.Layout(width='180px'))



    row_box = widgets.HBox([

        upload_chk,

        share_chk,

        folder_html,

        reviewer_input,

        resolved_email_html,

        ad_status,

        sync_status,

        share_status,

    ])

    row_box.layout.padding = '6px'

    row_box.layout.margin = '4px 0'



    row = {

        'folder_name': folder_name,

        'folder_path': folder_path,

        'upload_chk': upload_chk,

        'share_chk': share_chk,

        'reviewer_input': reviewer_input,

        'resolved_email_html': resolved_email_html,

        'ad_status': ad_status,

        'sync_status': sync_status,

        'share_status': share_status,

        'row_box': row_box,

        'remote_folder_id': None,

        'remote_web_url': "",

        'resolved_email': "",

        'is_valid': False,

        'error': "",

        'root_break_status': "",

        'principal_id': "",

        'roledef_id_used': "",

        'grant_status': "",

    }



    _bind_row_callbacks(row)

    _revalidate_row(row, trigger_summary=False)

    return row





def _refresh_rows(_=None):

    global s5_rows, s5_ad_email_set, s5_ad_name_map, s5_stage4_active_dir



    s5_output.clear_output()

    s5_status.value = "<span style='color:blue;'>Refreshing reviewer folders...</span>"



    ok, ad_email_set, ad_name_map, cache_path, err = _load_latest_ad_identity_index()

    if not ok:

        s5_rows = []

        s5_ad_email_set = set()

        s5_ad_name_map = {}

        s5_table_box.children = [widgets.HTML(f"<span style='color:red;'>❌ {html.escape(err)}</span>")]

        s5_status.value = f"<span style='color:red;'>❌ {html.escape(err)}</span>"

        _update_summary()

        return



    s5_ad_email_set = ad_email_set

    s5_ad_name_map = ad_name_map



    folders = _list_stage4_subfolders()

    if not folders:

        s5_rows = []

        target_hint = s5_stage4_active_dir if s5_stage4_active_dir else STAGE4_ROOT_DIR

        s5_table_box.children = [widgets.HTML(

            f"<span style='color:red;'>❌ No reviewer subfolders found in {html.escape(target_hint)}</span>"

        )]

        s5_status.value = "<span style='color:red;'>❌ No Stage 4 subfolders found</span>"

        _update_summary()

        return



    header = widgets.HBox([

        widgets.HTML(value="<b>Upload</b>", layout=widgets.Layout(width='70px')),

        widgets.HTML(value="<b>Grant Edit (SPO)</b>", layout=widgets.Layout(width='120px')),

        widgets.HTML(value="<b>Subfolder</b>", layout=widgets.Layout(width='220px')),

        widgets.HTML(value="<b>Reviewer (name/email)</b>", layout=widgets.Layout(width='220px')),

        widgets.HTML(value="<b>Resolved AD Email</b>", layout=widgets.Layout(width='260px')),

        widgets.HTML(value="<b>AD Match</b>", layout=widgets.Layout(width='360px')),

        widgets.HTML(value="<b>Sync Status</b>", layout=widgets.Layout(width='180px')),

        widgets.HTML(value="<b>Share Status</b>", layout=widgets.Layout(width='180px')),

    ])

    header.layout.padding = '6px'

    header.layout.border = '1px solid #bbb'



    s5_rows = [_build_row(f['name'], f['path']) for f in folders]



    rows_ui = [header] + [r['row_box'] for r in s5_rows]

    s5_table_box.children = rows_ui



    s5_select_all_upload.value = True

    s5_select_all_share.value = False



    _update_summary()

    s5_status.value = (

        f"<span style='color:green;'>✅ Loaded {len(s5_rows)} reviewers | App folder: {html.escape(os.path.basename(s5_stage4_active_dir))} | AD cache: {html.escape(os.path.basename(cache_path))}</span>"

    )





def _apply_select_all_upload(change):

    if change['name'] != 'value':

        return

    for row in s5_rows:

        row['upload_chk'].value = bool(change['new'])





def _apply_select_all_share(change):

    if change['name'] != 'value':

        return

    for row in s5_rows:

        row['share_chk'].value = bool(change['new'])





def _run_selected_actions(_):

    s5_output.clear_output()

    s5_btn_run.disabled = True



    try:

        if not s5_rows:

            s5_status.value = "<span style='color:red;'>❌ No rows available. Refresh first.</span>"

            return



        if not s5_target_confirmed:

            s5_status.value = (

                "<span style='color:#d9534f;'>❌ Target folder is locked. "

                "Select from tree or paste URL first.</span>"

            )

            return



        target_url = s5_url_input.value.strip()



        graph_headers, err = _get_graph_headers_from_stage1()

        if not graph_headers:

            s5_status.value = f"<span style='color:red;'>❌ {html.escape(err)}</span>"

            return



        spo_headers, spo_host, spo_err = _get_spo_headers_from_stage1()

        if not spo_headers:

            s5_status.value = f"<span style='color:red;'>❌ {html.escape(spo_err)}</span>"

            return



        target = _resolve_target_folder(target_url, graph_headers)

        drive_id = target['drive_id']

        target_folder_id = target['item_id']



        s5_log("=" * 70)

        s5_log("Stage 5 started")

        s5_log(f"Target folder: {target['web_url']}")

        s5_log(f"Target source: {target.get('target_source', 'unknown')}")

        if target.get('target_source') == 'env':

            s5_log(f"Fallback site: {target.get('fallback_site', '-')}")

            s5_log(f"Fallback path: {target.get('fallback_path', '-')}")

        s5_log(f"SPO host: {spo_host}")



        upload_rows = [r for r in s5_rows if r['upload_chk'].value]

        share_rows = [r for r in s5_rows if r['share_chk'].value]



        s5_log(f"Upload selected rows: {len(upload_rows)}")

        s5_log(f"Grant Edit selected rows: {len(share_rows)}")

        if share_rows:

            s5_log("[TROUBLESHOOT] Grant Edit (SPO REST) checks:")

            s5_log("[TROUBLESHOOT] 1) Stage 1 has SharePoint token and host configured (SHAREPOINT_HOST)")

            s5_log("[TROUBLESHOOT] 2) root_break_status is ok/already_unique")

            s5_log("[TROUBLESHOOT] 3) grant_status is granted/already_exists and verified=True")

            s5_log("[TROUBLESHOOT] 4) folder webUrl host must match SHAREPOINT_HOST")



        # Upload phase

        for row in s5_rows:

            row['sync_status'].value = "<span style='color:#999;'>Skipped</span>"



        for row in upload_rows:

            folder_name = row['folder_name']

            local_folder = row['folder_path']

            try:

                s5_log(f"[UPLOAD] {folder_name}")

                remote_folder = _ensure_child_folder(drive_id, target_folder_id, folder_name, graph_headers)

                row['remote_folder_id'] = remote_folder.get('id')

                row['remote_web_url'] = remote_folder.get('webUrl', '')



                file_count = _sync_local_folder_to_remote(

                    local_folder=local_folder,

                    drive_id=drive_id,

                    remote_folder_item_id=row['remote_folder_id'],

                    headers=graph_headers,

                    logger=s5_log,

                )



                row['sync_status'].value = f"<span style='color:green;'>✅ Synced ({file_count} files)</span>"

            except Exception as e:

                row['sync_status'].value = f"<span style='color:#d9534f;'>❌ {html.escape(str(e))}</span>"



        # Grant Edit phase

        for row in s5_rows:

            row['share_status'].value = "<span style='color:#999;'>Skipped</span>"
            row['root_break_status'] = ""
            row['principal_id'] = ""
            row['roledef_id_used'] = ""
            row['grant_status'] = ""



        for row in share_rows:

            folder_name = row['folder_name']



            if not row['is_valid']:

                row['share_status'].value = "<span style='color:#d9534f;'>❌ Skipped: AD invalid</span>"

                continue



            try:

                if not row['remote_folder_id']:

                    existing_folder = _find_child_folder_by_name(drive_id, target_folder_id, folder_name, graph_headers)

                    if existing_folder:

                        row['remote_folder_id'] = existing_folder.get('id')

                        row['remote_web_url'] = existing_folder.get('webUrl', '')



                if not row['remote_folder_id']:

                    row['share_status'].value = "<span style='color:#d9534f;'>❌ Target folder not found on SharePoint</span>"

                    s5_log(f"[SHARE][ERROR] {folder_name}: target folder not found")

                    continue



                if not row['remote_web_url']:

                    row['share_status'].value = "<span style='color:#d9534f;'>❌ Missing folder web URL for SPO grant</span>"

                    s5_log(f"[SHARE][ERROR] {folder_name}: missing folder web URL")

                    continue



                s5_log(

                    f"[SHARE] {folder_name} -> {row['resolved_email']} | folder_id={row['remote_folder_id']}"

                )



                share_result = _grant_spo_edit_on_root_folder(

                    folder_web_url=row['remote_web_url'],

                    target_email=row['resolved_email'],

                    spo_headers=spo_headers,

                    spo_host=spo_host,

                )

                row['root_break_status'] = str(share_result.get('root_break_status', ''))

                row['principal_id'] = str(share_result.get('principal_id', ''))

                row['roledef_id_used'] = str(share_result.get('roledef_id_used', ''))

                row['grant_status'] = str(share_result.get('grant_status', ''))



                s5_log(

                    f"[SHARE] root_break={row['root_break_status']} "

                    f"grant_status={row['grant_status']} "

                    f"verified={share_result.get('verified')} "

                    f"principal_id={row['principal_id']} "

                    f"roledef_id={row['roledef_id_used']}"

                )



                row['share_status'].value = (

                    f"<span style='color:green;'>✅ Root folder Edit granted to {html.escape(row['resolved_email'])}</span>"

                )



            except Exception as e:

                row['share_status'].value = f"<span style='color:#d9534f;'>❌ {html.escape(str(e))}</span>"

                s5_log(f"[SHARE][ERROR] {folder_name}: {e}")



        _update_summary()

        s5_status.value = "<span style='color:green;'>✅ Stage 5 completed. Review row statuses below.</span>"

        s5_log("Stage 5 completed")



    except Exception as e:

        s5_status.value = f"<span style='color:red;'>❌ Stage 5 failed: {html.escape(str(e))}</span>"

        s5_log(f"[ERROR] {e}")



    finally:

        s5_btn_run.disabled = not s5_target_confirmed



# ============================================

# Bind and render UI

# ============================================



s5_select_all_upload.observe(_apply_select_all_upload, names='value')

s5_url_input.observe(_on_s5_url_input_change, names='value')

